/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;
    const totalCells = m * n;

    // The path length is always m + n - 1.
    // We need to find the minimum XOR sum among all paths.
    // Since m*n <= 1000, we can use dynamic programming or a meet-in-the-middle approach.

    // Meet-in-the-middle approach is suitable here because the path length is small (<= 1000 in total, but the length of a path is m+n-1).
    // Since m*n <= 1000, max path length is 1000. 
    // A full DP table of size m*n would work, but let's use the meet-in-the-middle idea based on the path length.

    // The total number of steps is m + n - 2. The halfway point is around (m+n-2)/2 steps.
    const targetSteps = Math.floor((m + n - 2) / 2);

    // Map to store XOR sums reachable at a specific cell (i, j) after 'k' steps.
    // key: string representation "i,j", value: Set of XOR sums
    // Since we are iterating by steps, we only need to store results for the current and next step layer.

    // dp[k] will be a Map: "i,j" -> Set<xor_sum> for all cells (i, j) reachable in exactly k steps.
    // Since k is the number of steps taken, the number of cells reached is k+1.

    // We use a simpler structure: dp[k] stores the set of {xor_sum, i, j} reachable in k steps.
    // However, given the constraints, let's optimize the DP state.

    // Let's use DP based on the sum of coordinates (i + j). This represents the number of steps taken (i+j).
    // dp[s] = Map<string, Set<number>> where s = i + j.
    // The key is "i,j" (though we only need to store values for reachable cells).
    // The value is the set of possible XOR sums ending at (i, j) where i+j=s.

    // Max sum of coordinates is m-1 + n-1 = m+n-2.
    const maxCoordSum = m + n - 2;

    // dp[s] will be a Map: "i,j" -> Set<number>
    // We only need to store the XOR sums reachable at a cell (i, j) where i+j = s.
    const dp = new Array(maxCoordSum + 1);
    for (let s = 0; s <= maxCoordSum; s++) {
        dp[s] = new Map();
    }

    // Base case: Start at (0, 0). Sum = 0.
    const initialXor = grid[0][0];
    const startKey = "0,0";
    dp[0].set(startKey, new Set([initialXor]));

    for (let s = 0; s < maxCoordSum; s++) {
        if (dp[s].size === 0) continue;

        for (const [key, xorSet] of dp[s].entries()) {
            const parts = key.split(',');
            const r = parseInt(parts[0]);
            const c = parseInt(parts[1]);

            for (const currentXor of xorSet) {
                // Move Down: (r + 1, c)
                if (r + 1 < m) {
                    const nr = r + 1;
                    const nc = c;
                    const nextXor = currentXor ^ grid[nr][nc];
                    const nextKey = `${nr},${nc}`;

                    if (!dp[s + 1].has(nextKey)) {
                        dp[s + 1].set(nextKey, new Set());
                    }
                    dp[s + 1].get(nextKey).add(nextXor);
                }

                // Move Right: (r, c + 1)
                if (c + 1 < n) {
                    const nr = r;
                    const nc = c + 1;
                    const nextXor = currentXor ^ grid[nr][nc];
                    const nextKey = `${nr},${nc}`;

                    if (!dp[s + 1].has(nextKey)) {
                        dp[s + 1].set(nextKey, new Set());
                    }
                    dp[s + 1].get(nextKey).add(nextXor);
                }
            }
        }
    }

    // The result is in dp[m + n - 2] at key "m-1, n-1"
    const finalSum = m + n - 2;
    const finalKey = `${m - 1},${n - 1}`;

    if (dp[finalSum].has(finalKey)) {
        const finalXors = dp[finalSum].get(finalKey);
        let minXor = Infinity;
        for (const xor of finalXors) {
            minXor = Math.min(minXor, xor);
        }
        return minXor;
    }

    // Should not happen for valid inputs
    return -1; 
}

